import React, { useState, useEffect } from "react";
import axios from "axios";
import Pagination from "../components"; // <-- tu componente de paginación

export default function Productos() {
  const [productos, setProductos] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [productoActual, setProductoActual] = useState({
    ProductoID: null,
    Nombre: "",
    Descripcion: "",
    Precio: "",
    Stock: "",
    CategoriaID: "",
    Imagen: null,
  });
  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");
  const [imagenModal, setImagenModal] = useState(null);

  // Paginación por categoría
  const productosPorPagina = 6;
  const [paginaPorCategoria, setPaginaPorCategoria] = useState({});

  useEffect(() => {
    obtenerProductos();
    obtenerCategorias();
  }, []);

  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    }
  };

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
      // Inicializamos paginación por categoría
      const inicial = {};
      res.data.forEach((cat) => (inicial[cat.id] = 1));
      setPaginaPorCategoria(inicial);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const handleChange = (e) => {
    if (e.target.name === "Imagen") {
      setProductoActual({ ...productoActual, Imagen: e.target.files[0] });
    } else {
      setProductoActual({ ...productoActual, [e.target.name]: e.target.value });
    }
  };

  const abrirModalAgregar = () => {
    setProductoActual({
      ProductoID: null,
      Nombre: "",
      Descripcion: "",
      Precio: "",
      Stock: "",
      CategoriaID: "",
      Imagen: null,
    });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (producto) => {
    setProductoActual(producto);
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarProducto = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData();
      formData.append("Nombre", productoActual.Nombre);
      formData.append("Descripcion", productoActual.Descripcion);
      formData.append("Precio", productoActual.Precio);
      formData.append("Stock", productoActual.Stock);
      formData.append("CategoriaID", productoActual.CategoriaID);
      if (productoActual.Imagen) formData.append("Imagen", productoActual.Imagen);

      if (modoEdicion) {
        await axios.put(
          `http://localhost:5000/api/productos/${productoActual.ProductoID}`,
          formData,
          { headers: { "Content-Type": "multipart/form-data" } }
        );
      } else {
        await axios.post("http://localhost:5000/api/productos", formData, {
          headers: { "Content-Type": "multipart/form-data" },
        });
      }

      setShowModal(false);
      obtenerProductos();
    } catch (error) {
      console.error("❌ Error al guardar producto:", error);
    }
  };

  const eliminarProducto = async (id) => {
    if (window.confirm("¿Seguro que deseas eliminar este producto?")) {
      try {
        await axios.delete(`http://localhost:5000/api/productos/${id}`);
        obtenerProductos();
      } catch (error) {
        console.error("❌ Error al eliminar producto:", error);
      }
    }
  };

  const cambiarPaginaCategoria = (catId, numero) => {
    setPaginaPorCategoria({ ...paginaPorCategoria, [catId]: numero });
  };

  // Agrupar productos por categoría y aplicar búsqueda
  const categoriasConProductos = categorias.map((cat) => {
    const filtrados = productos.filter(
      (p) =>
        p.CategoriaID === cat.id &&
        (p.Nombre.toLowerCase().includes(busqueda.toLowerCase()) ||
          p.Descripcion.toLowerCase().includes(busqueda.toLowerCase()))
    );
    const paginaActual = paginaPorCategoria[cat.id] || 1;
    const indiceInicio = (paginaActual - 1) * productosPorPagina;
    const indiceFin = indiceInicio + productosPorPagina;
    const productosPaginados = filtrados.slice(indiceInicio, indiceFin);

    return {
      ...cat,
      productosPaginados,
      totalItems: filtrados.length,
      paginaActual,
    };
  }).filter((cat) => cat.productosPaginados.length > 0);

  return (
    <div className="container mt-5">
      {/* Buscador y agregar */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <input
          type="text"
          placeholder="Buscar producto por nombre o descripción..."
          className="form-control w-50"
          value={busqueda}
          onChange={(e) => setBusqueda(e.target.value)}
        />
        <button className="btn btn-success btn-lg" onClick={abrirModalAgregar}>
          ➕ Agregar Producto
        </button>
      </div>

      {/* Productos por categoría */}
      {categoriasConProductos.map((cat) => (
        <div key={cat.id} className="mb-5">
          <h3 className="mb-3">{cat.nombre}</h3>
          <div className="row g-3">
            {cat.productosPaginados.map((p) => (
              <div key={p.ProductoID} className="col-md-3">
                <div className="card shadow-sm h-100">
                  {p.Imagen && (
                    <img
                      src={`http://localhost:5000/uploads/${p.Imagen}`}
                      alt={p.Nombre}
                      className="card-img-top"
                      style={{ cursor: "pointer", height: "180px", objectFit: "cover" }}
                      onClick={() => setImagenModal(p.Imagen)}
                    />
                  )}
                  <div className="card-body d-flex flex-column justify-content-between">
                    <h5 className="card-title">{p.Nombre}</h5>
                    <p className="card-text">${p.Precio}</p>
                    <p className="card-text">Stock: {p.Stock}</p>
                    <div className="mt-2 d-flex justify-content-between">
                      <button
                        className="btn btn-warning btn-sm"
                        onClick={() => abrirModalEditar(p)}
                      >
                        ✏️ Editar
                      </button>
                      <button
                        className="btn btn-danger btn-sm"
                        onClick={() => eliminarProducto(p.ProductoID)}
                      >
                        🗑️ Eliminar
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Paginación reutilizable */}
          <Pagination
            totalItems={cat.totalItems}
            itemsPerPage={productosPorPagina}
            currentPage={cat.paginaActual}
            onPageChange={(page) => cambiarPaginaCategoria(cat.id, page)}
          />
        </div>
      ))}

      {productos.length === 0 && (
        <p className="text-center text-muted">No hay productos encontrados.</p>
      )}

      {/* Modal agregar/editar */}
      {showModal && (
        <div
          className="modal fade show"
          style={{ display: "block", backgroundColor: "rgba(0,0,0,0.6)" }}
        >
          <div className="modal-dialog modal-lg modal-dialog-centered">
            <div className="modal-content p-4 shadow-lg">
              <div className="modal-header">
                <h5 className="modal-title fw-bold">
                  {modoEdicion ? "Editar Producto" : "Agregar Nuevo Producto"}
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  onClick={() => setShowModal(false)}
                ></button>
              </div>
              <div className="modal-body">
                <form onSubmit={guardarProducto} encType="multipart/form-data">
                  <div className="row g-3">
                    <div className="col-md-6">
                      <label className="form-label">Nombre</label>
                      <input
                        type="text"
                        name="Nombre"
                        value={productoActual.Nombre}
                        onChange={handleChange}
                        className="form-control"
                        required
                      />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label">Precio</label>
                      <input
                        type="number"
                        step="0.01"
                        name="Precio"
                        value={productoActual.Precio}
                        onChange={handleChange}
                        className="form-control"
                        required
                      />
                    </div>
                    <div className="col-md-12">
                      <label className="form-label">Descripción</label>
                      <textarea
                        name="Descripcion"
                        value={productoActual.Descripcion}
                        onChange={handleChange}
                        className="form-control"
                        rows="2"
                      ></textarea>
                    </div>
                    <div className="col-md-6">
                      <label className="form-label">Stock</label>
                      <input
                        type="number"
                        name="Stock"
                        value={productoActual.Stock}
                        onChange={handleChange}
                        className="form-control"
                        required
                      />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label">Categoría</label>
                      <select
                        name="CategoriaID"
                        value={productoActual.CategoriaID || ""}
                        onChange={handleChange}
                        className="form-select"
                        required
                      >
                        <option value="">Seleccione una categoría</option>
                        {categorias.map((cat) => (
                          <option key={cat.id} value={cat.id}>
                            {cat.nombre}
                          </option>
                        ))}
                      </select>
                    </div>
                    <div className="col-md-12">
                      <label className="form-label">Imagen</label>
                      <input
                        type="file"
                        name="Imagen"
                        onChange={handleChange}
                        className="form-control"
                      />
                    </div>
                  </div>
                  <div className="mt-4 text-end">
                    <button
                      type="button"
                      className="btn btn-secondary me-2"
                      onClick={() => setShowModal(false)}
                    >
                      Cancelar
                    </button>
                    <button type="submit" className="btn btn-primary">
                      {modoEdicion ? "Guardar Cambios" : "Guardar Producto"}
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal para imagen grande */}
      {imagenModal && (
        <div
          className="modal fade show"
          style={{ display: "block", backgroundColor: "rgba(0,0,0,0.8)" }}
          onClick={() => setImagenModal(null)}
        >
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content p-0 border-0 bg-transparent">
              <img
                src={`http://localhost:5000/uploads/${imagenModal}`}
                alt="Producto"
                className="img-fluid rounded"
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
